    } else { // 'c'
      return categorical({ps: [0.1, 0.1, 0.8], vs: ['bagel', 'cookie', 'doughnut']});
    }
  };

  // Probability of choosing an action given goal and deceptive
  // If not deceptive: pick action whose outcome IS goal food (maximize prob of getting goal)
  // If deceptive: pick action whose outcome AVOIDS goal food

  // Action utilities: expected probability of getting goal food
  var actionUtility = function(action, goalFood) {
