// Hidden Markov Model for sentence generation
// POS tags: 'N' (noun), 'V' (verb), 'stop'
// Words: N -> {dogs, cats}, V -> {chase, sleep}

// Dirichlet-drift priors for transition distributions
// From 'start': can go to N or V
// From N: can go to V or stop
// From V: can go to N or stop

var transitionParams = {
  'start': [1, 1, 0.01],  // [N, V, stop] - sentences start with N or V
  'N': [0.1, 2, 1],       // [N, V, stop] - after noun, likely verb or stop
  'V': [2, 0.1, 1]        // [N, V, stop] - after verb, likely noun or stop
};

var posStates = ['N', 'V', 'stop'];

var emissionParams = {
  'N': [1, 1],   // [dogs, cats]
  'V': [1, 1]    // [chase, sleep]
};

var nounWords = ['dogs', 'cats'];
var verbWords = ['chase', 'sleep'];

// Sample transition distributions using Dirichlet
var transitionDists = {
  'start': dirichlet(Vector(transitionParams['start'])),
  'N': dirichlet(Vector(transitionParams['N'])),
  'V': dirichlet(Vector(transitionParams['V']))
};

// Sample emission distributions using Dirichlet
var emissionDists = {
  'N': dirichlet(Vector(emissionParams['N'])),
  'V': dirichlet(Vector(emissionParams['V']))
};

// Convert dirichlet sample to categorical distribution
var makeCategorical = function(vec, support) {
  return Categorical({ps: vec, vs: support});
};

// Transition function: given current POS, sample next POS
var transition = function(currentPos) {
  var ps = transitionDists[currentPos];
  return sample(makeCategorical(ps, posStates));
};

// Emission function: given POS, sample a word
var emit = function(pos) {
  if (pos === 'N') {
    var ps = emissionDists['N'];
    return sample(makeCategorical(ps, nounWords));
  } else if (pos === 'V') {
    var ps = emissionDists['V'];
    return sample(makeCategorical(ps, verbWords));
  } else {
    return null; // stop state emits nothing
  }
};

// Generate a sentence starting from a given state
var generateSentence = function(currentPos) {
  var nextPos = transition(currentPos);
  if (nextPos === 'stop') {
    return [];
  } else {
    var word = emit(nextPos);
    var rest = generateSentence(nextPos);
    return [word].concat(rest);
  }
};

